import { memo, useCallback, useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import { MapPinned, UserPlus } from 'lucide-react';
import Badge from './ui/Badge';
import { cn } from '../lib/cn';
import { IDanfe, IInvoiceSearchContext, ITrip } from '../types/types';
import { CardsDanfe, ContainerCards, ContainerItems, DescriptionColumns, ItemsScrollArea, ListItems, TitleCard, TotalQuantity } from '../style/CardDanfes';
import { formatDateBR } from '../utils/dateDisplay';
import {
  DANFE_STATUS_LEGEND,
  DanfeLegendKey,
  getDanfeLegendItem,
  getOccurrenceTone,
  getOperationalStatusCardClassName,
  getOperationalStatusLabel,
  getOperationalStatusTone,
  getSemanticToneClassName,
  matchesDanfeLegendFilter,
} from '../utils/statusStyles';
import { API_URL } from '../data';
import { normalizeCityLabel, normalizeTextValue, sanitizeDanfeTextFields } from '../utils/textNormalization';

interface CardDanfesProps {
  danfes: IDanfe[];
  driverByInvoice?: Record<string, string>;
  invoiceContextByNf?: Record<string, IInvoiceSearchContext>;
  showLegend?: boolean;
  onDanfeUpdated?: (danfe: IDanfe) => void;
  assignableTrips?: ITrip[];
  onAssignDanfeToTrip?: (danfe: IDanfe, tripId: number) => Promise<void>;
  onOpenReturnBatch?: (batchCode: string, invoiceNumber: string) => void;
}

const RETURN_TYPE_LABELS: Record<string, string> = {
  total: 'Devolucao total',
  partial: 'Devolucao parcial',
  sobra: 'Sobra',
  coleta: 'Coleta',
};

const PRIORITY_CARD_STATUS_OVERRIDES = new Set(['retained', 'returned', 'cancelled', 'redelivery']);
const ROUTE_TRACEABLE_STATUSES = new Set(['assigned', 'delivered', 'completed', 'redelivery']);

function getOccurrenceStatusLabel(value: unknown) {
  return String(value || '').trim().toLowerCase() === 'resolved'
    ? 'Ocorrencia resolvida'
    : 'Ocorrencia pendente';
}

function getOccurrenceDetailStatusLabel(value: unknown) {
  return String(value || '').trim().toLowerCase() === 'resolved' ? 'Resolvida' : 'Pendente';
}

function getCteStatusLabel(value: unknown) {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'authorized') return 'CT-e autorizado';
  if (normalized === 'rejected') return 'CT-e rejeitado';
  if (normalized === 'cancelled') return 'CT-e cancelado';
  if (normalized === 'failed') return 'Falha no CT-e';
  if (normalized === 'ready') return 'CT-e pronto';
  if (normalized === 'draft') return 'CT-e rascunho';
  return 'CT-e vinculado';
}

function getCteStatusTone(value: unknown) {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'authorized') return 'success' as const;
  if (normalized === 'rejected' || normalized === 'failed' || normalized === 'cancelled') return 'danger' as const;
  return 'warning' as const;
}

function resolveDisplayStatus(danfeStatus: unknown, invoiceContext?: IInvoiceSearchContext | null) {
  const baseStatus = String(danfeStatus || '').trim().toLowerCase();
  const tripNoteStatus = String(invoiceContext?.trip_note_status || '').trim().toLowerCase();

  if (PRIORITY_CARD_STATUS_OVERRIDES.has(tripNoteStatus) && tripNoteStatus !== baseStatus) {
    return tripNoteStatus;
  }

  return baseStatus;
}

function CardDanfes({
  danfes,
  driverByInvoice = {},
  invoiceContextByNf = {},
  showLegend = true,
  onDanfeUpdated,
  assignableTrips = [],
  onAssignDanfeToTrip,
  onOpenReturnBatch,
}: CardDanfesProps) {
  const [flippedCards, setFlippedCards] = useState<Record<string, boolean>>({});
  const [productsModalDanfe, setProductsModalDanfe] = useState<IDanfe | null>(null);
  const [replacementModalDanfe, setReplacementModalDanfe] = useState<IDanfe | null>(null);
  const [replacementInvoiceInput, setReplacementInvoiceInput] = useState('');
  const [replacementReasonInput, setReplacementReasonInput] = useState('Refaturada');
  const [replacementError, setReplacementError] = useState('');
  const [isLinkingReplacement, setIsLinkingReplacement] = useState(false);
  const [activeStatusFilter, setActiveStatusFilter] = useState<DanfeLegendKey | null>(null);
  const [assignmentModalDanfe, setAssignmentModalDanfe] = useState<IDanfe | null>(null);
  const [selectedTripId, setSelectedTripId] = useState('');
  const [isAssigningDanfe, setIsAssigningDanfe] = useState(false);
  const [assignmentError, setAssignmentError] = useState('');

  const filteredDanfes = useMemo(() => {
    if (!activeStatusFilter) return danfes;
    return danfes.filter((danfe) => matchesDanfeLegendFilter(danfe.status, activeStatusFilter));
  }, [activeStatusFilter, danfes]);

  const activeLegendItem = activeStatusFilter ? getDanfeLegendItem(activeStatusFilter) : null;

  const formatQuantity = (quantity: number | string, unit: string) => {
    const parsed = Number(quantity);
    if (!Number.isFinite(parsed)) {
      return `${String(quantity)} ${unit}`;
    }

    const formatted = new Intl.NumberFormat('pt-BR', {
      minimumFractionDigits: 0,
      maximumFractionDigits: 3,
    }).format(parsed);

    return `${formatted} ${unit}`;
  };

  function toggleFlip(key: string) {
    setFlippedCards((prev) => ({ ...prev, [key]: !prev[key] }));
  }

  function openProductsModal(danfe: IDanfe) {
    setProductsModalDanfe(danfe);
  }

  function closeProductsModal() {
    setProductsModalDanfe(null);
  }

  function openReplacementModal(danfe: IDanfe) {
    setReplacementModalDanfe(danfe);
    setReplacementInvoiceInput(danfe.replacement_invoice_number || '');
    setReplacementReasonInput(danfe.replacement_reason || 'Refaturada');
    setReplacementError('');
  }

  function openAssignmentModal(danfe: IDanfe) {
    setAssignmentModalDanfe(danfe);
    setSelectedTripId('');
    setAssignmentError('');
  }

  const closeAssignmentModal = useCallback((force = false) => {
    if (isAssigningDanfe && !force) return;
    setAssignmentModalDanfe(null);
    setSelectedTripId('');
    setAssignmentError('');
  }, [isAssigningDanfe]);

  async function handleAssignDanfeToTrip() {
    if (!assignmentModalDanfe || !onAssignDanfeToTrip) return;

    const tripId = Number(selectedTripId || 0);
    if (!Number.isFinite(tripId) || tripId <= 0) {
      setAssignmentError('Selecione uma rota para atribuir esta NF.');
      return;
    }

    try {
      setIsAssigningDanfe(true);
      setAssignmentError('');
      await onAssignDanfeToTrip(assignmentModalDanfe, tripId);
      closeAssignmentModal(true);
    } catch (error: any) {
      setAssignmentError(error?.response?.data?.error || error?.message || 'Nao foi possivel atribuir esta NF agora.');
    } finally {
      setIsAssigningDanfe(false);
    }
  }

  const closeReplacementModal = useCallback((force = false) => {
    if (isLinkingReplacement && !force) return;
    setReplacementModalDanfe(null);
    setReplacementInvoiceInput('');
    setReplacementReasonInput('Refaturada');
    setReplacementError('');
  }, [isLinkingReplacement]);

  async function handleLinkReplacementInvoice() {
    if (!replacementModalDanfe) return;

    const replacementInvoiceNumber = String(replacementInvoiceInput || '').trim();
    if (!replacementInvoiceNumber) {
      setReplacementError('Informe a NF substituta para vincular o refaturamento.');
      return;
    }

    try {
      setIsLinkingReplacement(true);
      setReplacementError('');

      const { data } = await axios.patch<IDanfe>(
        `${API_URL}/danfes/nf/${encodeURIComponent(replacementModalDanfe.invoice_number)}/replacement`,
        {
          replacementInvoiceNumber,
          replacementReason: String(replacementReasonInput || '').trim() || 'Refaturada',
          companyId: replacementModalDanfe.company_id || null,
        },
      );

      const updatedDanfe = sanitizeDanfeTextFields(data);
      onDanfeUpdated?.(updatedDanfe);

      if (replacementInvoiceNumber) {
        try {
          const replacementResponse = await axios.get<IDanfe>(`${API_URL}/danfes/nf/${encodeURIComponent(replacementInvoiceNumber)}`, {
            params: replacementModalDanfe.company_id ? { companyId: replacementModalDanfe.company_id } : undefined,
          });
          if (replacementResponse.data) {
            onDanfeUpdated?.(sanitizeDanfeTextFields(replacementResponse.data));
          }
        } catch {
          // noop: a NF substituta sera atualizada ao ser pesquisada novamente.
        }
      }

      closeReplacementModal(true);
    } catch (error: any) {
      setReplacementError(
        error?.response?.data?.error
          || 'Nao foi possivel vincular a NF substituta agora.',
      );
    } finally {
      setIsLinkingReplacement(false);
    }
  }

  useEffect(() => {
    if (!productsModalDanfe && !replacementModalDanfe && !assignmentModalDanfe) return undefined;

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        if (productsModalDanfe) {
          setProductsModalDanfe(null);
          return;
        }
        if (replacementModalDanfe && !isLinkingReplacement) {
          closeReplacementModal();
          return;
        }
        if (assignmentModalDanfe && !isAssigningDanfe) {
          closeAssignmentModal();
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [assignmentModalDanfe, closeAssignmentModal, closeReplacementModal, isAssigningDanfe, isLinkingReplacement, productsModalDanfe, replacementModalDanfe]);

  return (
    <>
      {showLegend && danfes.length ? (
        <div className="mx-auto mb-s3 w-full max-w-[1200px] rounded-lg border border-border bg-surface/90 p-s3" data-testid="danfe-status-legend">
          <div className="flex flex-wrap items-center gap-2">
            <p className="text-[11px] font-semibold uppercase tracking-[0.16em] text-muted">
              Legenda das bordas
            </p>
            {DANFE_STATUS_LEGEND.map((item) => {
              const isActive = activeStatusFilter === item.key;

              return (
                <button
                  key={item.key}
                  type="button"
                  onClick={() => setActiveStatusFilter((current) => (current === item.key ? null : item.key))}
                  aria-label={`Filtrar por ${item.label}`}
                  aria-pressed={isActive}
                  title={item.description}
                  className={cn(
                    'inline-flex items-center gap-2 rounded-full border px-2.5 py-1 text-[11px] font-semibold transition hover:brightness-95',
                    isActive ? getSemanticToneClassName(item.tone) : 'semantic-solid-neutral',
                  )}
                >
                  <span className={cn('h-2.5 w-2.5 rounded-full border-2 bg-card', item.borderClassName)} aria-hidden="true" />
                  {item.label}
                </button>
              );
            })}
            {activeLegendItem ? (
              <button
                type="button"
                onClick={() => setActiveStatusFilter(null)}
                aria-label="Limpar filtro de status"
                className="inline-flex items-center gap-2 rounded-full border semantic-solid-neutral px-2.5 py-1 text-[11px] font-semibold transition hover:brightness-95"
              >
                Fechar filtro
                <span aria-hidden="true">×</span>
              </button>
            ) : null}
          </div>
          {activeLegendItem ? (
            <p className="mt-2 text-xs text-muted">
              {`Filtro ativo: ${activeLegendItem.label}. Exibindo ${filteredDanfes.length} de ${danfes.length} NF(s).`}
            </p>
          ) : null}
        </div>
      ) : null}

      {filteredDanfes.length ? (
        <ContainerCards>
          {filteredDanfes.map((danfe) => {
            const key = String(danfe.barcode || danfe.invoice_number);
            const isFlipped = Boolean(flippedCards[key]);
            const invoiceNumber = String(danfe.invoice_number);
            const invoiceContext = invoiceContextByNf[invoiceNumber] || null;
            const resolvedDriverName = driverByInvoice[invoiceNumber] || invoiceContext?.driver_name || null;
            const customerName = normalizeTextValue(danfe.Customer?.name_or_legal_entity) || '-';
            const cityName = normalizeCityLabel(danfe.Customer?.city) || '-';
            const customerAddress = normalizeTextValue(danfe.Customer?.address) || '-';
            const returnTypeLabels = invoiceContext?.return_types?.length
              ? invoiceContext.return_types.map((type) => RETURN_TYPE_LABELS[type] || type)
              : [];
            const returnBatches = invoiceContext?.return_batches || [];
            const displayStatus = resolveDisplayStatus(danfe.status, invoiceContext);
            const replacementInvoiceNumber = normalizeTextValue(danfe.replacement_invoice_number) || null;
            const replacedInvoiceNumber = normalizeTextValue(danfe.replaced_invoice_number) || null;
            const danfeStatusLabel = getOperationalStatusLabel(displayStatus);
            const danfeStatusTone = getOperationalStatusTone(displayStatus);
            const latestOccurrence = invoiceContext?.latest_occurrence || null;
            const latestOccurrenceDescription = normalizeTextValue(latestOccurrence?.description) || 'Ocorrencia registrada para esta NF';
            const latestOccurrenceTone = latestOccurrence ? getOccurrenceTone(latestOccurrence.status) : 'warning';
            const creditLetterTone = invoiceContext?.credit_letter_pending_count ? 'warning' : 'success';
            const driverTone = resolvedDriverName ? 'success' : 'warning';
            const currentCte = danfe.current_cte || null;
            const currentCteLabel = currentCte ? getCteStatusLabel(currentCte.status) : null;
            const currentCteNumber = currentCte?.number ? `${currentCte.number}/${currentCte.series || '1'}` : `rascunho ${currentCte?.id || ''}`.trim();
            const canAssignToTrip = Boolean(
              onAssignDanfeToTrip
              && assignableTrips.length
              && !resolvedDriverName
              && String(danfe.status || '').trim().toLowerCase() === 'pending',
            );
            const lastTripId = Number(invoiceContext?.trip_id || 0);
            const canOpenLastTrip = ROUTE_TRACEABLE_STATUSES.has(displayStatus) && lastTripId > 0;
            const openLastTrip = () => {
              if (!canOpenLastTrip) return;
              const params = new URLSearchParams({
                nf: invoiceNumber,
                trip: String(lastTripId),
              });
              if (invoiceContext?.trip_date) params.set('date', invoiceContext.trip_date);
              window.location.hash = `#/delivery-monitoring?${params.toString()}`;
            };

            return (
              <div key={key} className="h-[350px] w-full max-w-[360px] [perspective:1200px]">
                <div
                  className="relative h-full w-full transition-transform duration-500"
                  style={{ transformStyle: 'preserve-3d', transform: isFlipped ? 'rotateY(180deg)' : 'none' }}
                >
                  <CardsDanfe
                    data-testid={`danfe-card-${invoiceNumber}`}
                    className={cn(
                      'absolute inset-0 select-text overflow-hidden',
                      getOperationalStatusCardClassName(displayStatus),
                    )}
                    style={{ backfaceVisibility: 'hidden' }}
                  >
                    <TitleCard className="shrink-0">
                      <h1>{`NF ${danfe.invoice_number}`}</h1>
                      <Badge
                        tone={driverTone}
                        className="absolute left-1/2 top-1.5 flex h-auto max-w-[72%] -translate-x-1/2 items-center gap-1 px-2 py-0.5 text-[10px] leading-tight"
                      >
                        <span className="truncate">{resolvedDriverName ? `Motorista: ${resolvedDriverName}` : 'Sem motorista'}</span>
                        {canAssignToTrip ? (
                          <button
                            type="button"
                            onClick={() => openAssignmentModal(danfe)}
                            className="inline-flex h-5 w-5 shrink-0 items-center justify-center rounded-full border border-current/40 bg-black/10 text-current transition hover:bg-black/20"
                            aria-label={`Atribuir NF ${danfe.invoice_number} a uma rota`}
                            title="Atribuir a uma rota"
                          >
                            <UserPlus className="h-3.5 w-3.5" />
                          </button>
                        ) : null}
                      </Badge>
                      <h4>{formatDateBR(danfe.invoice_date)}</h4>
                    </TitleCard>
                    <div className="min-h-0 flex flex-1 flex-col overflow-hidden">
                      <div className="mt-1 shrink-0">
                        <h4 className="break-words text-sm font-semibold leading-tight">{customerName}</h4>
                        <p className="break-words text-xs text-muted">{cityName}</p>
                        <div className="mt-2 flex flex-wrap gap-1.5">
                          <Badge tone={danfeStatusTone} className="h-auto px-2 py-0.5 text-[10px] leading-tight">
                            {danfeStatusLabel}
                          </Badge>
                          {canOpenLastTrip ? (
                            <button
                              type="button"
                              onClick={openLastTrip}
                              className="inline-flex items-center gap-1 rounded-full border border-sky-500/50 bg-sky-500/10 px-2 py-0.5 text-[10px] font-semibold text-sky-200 transition hover:bg-sky-500/20"
                              aria-label={`Abrir última rota da NF ${invoiceNumber}`}
                              title={`Abrir rota #${lastTripId} no monitoramento`}
                            >
                              <MapPinned className="h-3 w-3" />
                              {`Última rota #${lastTripId}`}
                            </button>
                          ) : null}
                          {invoiceContext?.occurrence_count ? (
                            <Badge tone="warning" className="h-auto px-2 py-0.5 text-[10px] leading-tight">
                              {`Ocorrencias: ${invoiceContext.occurrence_count}`}
                            </Badge>
                          ) : null}
                          {invoiceContext?.credit_letter_count ? (
                            <Badge tone={creditLetterTone} className="h-auto px-2 py-0.5 text-[10px] leading-tight">
                              {`Carta de credito: ${invoiceContext.credit_letter_pending_count > 0 ? 'pendente' : 'concluida'}`}
                            </Badge>
                          ) : null}
                          {returnTypeLabels.map((label) => (
                            <Badge
                              key={`${danfe.invoice_number}-return-type-${label}`}
                              tone="danger"
                              className="h-auto px-2 py-0.5 text-[10px] leading-tight"
                            >
                              {label}
                            </Badge>
                          ))}
                          {returnBatches.map((batch) => (
                            <button
                              key={`${danfe.invoice_number}-return-batch-${batch.batch_code}`}
                              type="button"
                              onClick={() => onOpenReturnBatch?.(batch.batch_code, invoiceNumber)}
                              disabled={!onOpenReturnBatch}
                              className="rounded-full disabled:cursor-default"
                              aria-label={`Abrir lote de devolucao ${batch.batch_code}`}
                            >
                              <Badge
                                tone={batch.is_sent ? 'success' : 'warning'}
                                className="h-auto px-2 py-0.5 text-[10px] leading-tight"
                              >
                                {`Lote ${batch.batch_code}: ${batch.is_sent ? 'enviado/finalizado' : 'pendente de envio'}`}
                              </Badge>
                            </button>
                          ))}
                          {replacementInvoiceNumber ? (
                            <Badge tone="neutral" className="h-auto px-2 py-0.5 text-[10px] leading-tight">
                              {`Refaturada: NF ${replacementInvoiceNumber}`}
                            </Badge>
                          ) : null}
                          {replacedInvoiceNumber ? (
                            <Badge tone="info" className="h-auto px-2 py-0.5 text-[10px] leading-tight">
                              {`Substitui NF ${replacedInvoiceNumber}`}
                            </Badge>
                          ) : null}
                          {currentCte ? (
                            <Badge tone={getCteStatusTone(currentCte.status)} className="h-auto px-2 py-0.5 text-[10px] leading-tight">
                              {`${currentCteLabel}: ${currentCteNumber}`}
                            </Badge>
                          ) : null}
                        </div>
                        {latestOccurrence ? (
                          <div
                            className={cn(
                              'mt-2 rounded-md border px-2 py-1 text-[11px]',
                              getSemanticToneClassName(latestOccurrenceTone, 'panel'),
                            )}
                            title={latestOccurrenceDescription}
                          >
                            <p className="text-[10px] font-semibold uppercase tracking-wide">
                              {getOccurrenceStatusLabel(latestOccurrence.status)}
                            </p>
                            <p className="truncate">{latestOccurrenceDescription}</p>
                          </div>
                        ) : null}
                      </div>

                      <ContainerItems className="min-h-0 flex-1">
                        {danfe.DanfeProducts.length > 4 && (
                          <div className="flex items-center justify-between gap-2 rounded-md border border-border bg-surface-2 px-2 py-1">
                            <p className="text-[10px] font-medium text-muted">
                              Lista grande de itens.
                            </p>
                            <button
                              type="button"
                              onClick={() => openProductsModal(danfe)}
                              className="inline-flex h-6 shrink-0 items-center rounded-md border border-accent/45 bg-accent/15 px-2 text-[10px] font-semibold text-text-accent transition hover:bg-accent/25"
                              aria-label={`Abrir lista completa de produtos da NF ${danfe.invoice_number}`}
                            >
                              Ver todos
                            </button>
                          </div>
                        )}
                        <DescriptionColumns className="shrink-0 pr-1">
                          <span>Codigo</span>
                          <span>Descricao</span>
                          <span>Qtd</span>
                        </DescriptionColumns>
                        <ItemsScrollArea aria-label={`Itens da NF ${danfe.invoice_number}`}>
                          {danfe.DanfeProducts.map((item) => (
                            <ListItems key={`${danfe.invoice_number}-${item.Product.code}`}>
                              <li>{item.Product.code}</li>
                              <li title={normalizeTextValue(item.Product.description)}>{normalizeTextValue(item.Product.description)}</li>
                              <li>{formatQuantity(item.quantity, item.type)}</li>
                            </ListItems>
                          ))}
                        </ItemsScrollArea>
                      </ContainerItems>
                    </div>

                    <TotalQuantity className="mt-2 shrink-0 flex items-center justify-between gap-2">
                      <p className="min-w-0 truncate">{`Quantidade Total: ${formatQuantity(danfe.total_quantity, 'UN')}`}</p>
                      <button
                        type="button"
                        onClick={() => toggleFlip(key)}
                        className="inline-flex h-7 shrink-0 items-center rounded-md border border-border bg-surface-2/85 px-2 text-[11px] font-semibold text-text transition hover:border-accent/60 hover:text-text-accent"
                        aria-label={`Mostrar detalhes da NF ${danfe.invoice_number}`}
                      >
                        Detalhes
                      </button>
                    </TotalQuantity>
                  </CardsDanfe>

                  <CardsDanfe
                    className={cn(
                      'absolute inset-0 select-text overflow-hidden',
                      getOperationalStatusCardClassName(displayStatus),
                    )}
                    style={{ backfaceVisibility: 'hidden', transform: 'rotateY(180deg)' }}
                  >
                    <TitleCard className="shrink-0">
                      <h1>{`NF ${danfe.invoice_number}`}</h1>
                      <h4>Detalhes</h4>
                    </TitleCard>
                    <div className="mt-2 min-h-0 flex-1 overflow-y-auto pr-1">
                      <div className="space-y-2 text-sm">
                        <p><strong>Cliente:</strong> {customerName}</p>
                        <p><strong>Status:</strong> {danfeStatusLabel}</p>
                        <p><strong>Endereco:</strong> {customerAddress}</p>
                        <p><strong>Cidade:</strong> {cityName}</p>
                        <p><strong>Telefone:</strong> {normalizeTextValue(danfe.Customer.phone) || '-'}</p>
                        <p><strong>Carga:</strong> {danfe.load_number || '-'}</p>
                        <p><strong>Motorista:</strong> {resolvedDriverName || 'Sem motorista'}</p>
                        {canOpenLastTrip ? (
                          <p>
                            <strong>Última rota:</strong>{' '}
                            <button
                              type="button"
                              onClick={openLastTrip}
                              className="font-semibold text-text-accent underline decoration-dotted underline-offset-2"
                            >
                              {`#${lastTripId}${invoiceContext?.trip_run_number ? ` · saída #${invoiceContext.trip_run_number}` : ''}${invoiceContext?.trip_date ? ` · ${formatDateBR(invoiceContext.trip_date)}` : ''}`}
                            </button>
                          </p>
                        ) : null}
                        {currentCte ? (
                          <>
                            <p><strong>CT-e atual:</strong> {`${currentCteLabel} (${currentCteNumber})`}</p>
                            <p><strong>CFOP sugerido/usado:</strong> {currentCte.cfop || '-'}</p>
                            <p><strong>Tomador:</strong> {currentCte.taker_role || '-'}</p>
                            <p><strong>Valor do frete:</strong> {currentCte.total_service_value || '-'}</p>
                          </>
                        ) : (
                          <p><strong>CT-e:</strong> nenhum CT-e vinculado ainda.</p>
                        )}
                        {replacementInvoiceNumber ? (
                          <p>
                            <strong>Motivo/observacao:</strong>{' '}
                            {`${normalizeTextValue(danfe.replacement_reason) || 'Refaturada'} — NF nova: ${replacementInvoiceNumber}`}
                          </p>
                        ) : null}
                        {replacedInvoiceNumber ? (
                          <p><strong>Substitui a NF cancelada:</strong> {replacedInvoiceNumber}</p>
                        ) : null}
                        {normalizeTextValue(danfe.status) === 'cancelled' && !replacementInvoiceNumber ? (
                          <button
                            type="button"
                            onClick={() => openReplacementModal(danfe)}
                            className="inline-flex h-8 items-center rounded-md border border-border bg-surface-2/85 px-2 text-xs font-semibold text-text transition hover:border-accent/60 hover:text-text-accent"
                          >
                            Vincular NF substituta
                          </button>
                        ) : null}
                        {latestOccurrence ? (
                          <>
                            <p><strong>Ultima ocorrencia:</strong> {latestOccurrenceDescription}</p>
                            <p><strong>Status da ocorrencia:</strong> {getOccurrenceDetailStatusLabel(latestOccurrence.status)}</p>
                          </>
                        ) : null}
                        {invoiceContext ? (
                          <>
                            <p>
                              <strong>Ocorrencias:</strong>
                              {` ${invoiceContext.occurrence_count} (pendentes: ${invoiceContext.occurrence_pending_count} | resolvidas: ${invoiceContext.occurrence_resolved_count})`}
                            </p>
                            <p>
                              <strong>Carta de credito:</strong>
                              {` ${invoiceContext.credit_letter_count ? `${invoiceContext.credit_letter_pending_count} pendente(s) / ${invoiceContext.credit_letter_completed_count} concluida(s)` : 'nenhuma'}`}
                            </p>
                            <p>
                              <strong>Devolucoes:</strong>
                              {` ${returnTypeLabels.length ? returnTypeLabels.join(', ') : 'nenhuma'}`}
                            </p>
                            {returnBatches.length ? returnBatches.map((batch) => (
                              <p key={`${danfe.invoice_number}-return-detail-${batch.batch_code}`}>
                                <strong>Lote da devolucao:</strong>{' '}
                                <button
                                  type="button"
                                  onClick={() => onOpenReturnBatch?.(batch.batch_code, invoiceNumber)}
                                  disabled={!onOpenReturnBatch}
                                  className="font-semibold text-text-accent underline decoration-dotted underline-offset-2 disabled:cursor-default disabled:no-underline"
                                >
                                  {batch.batch_code}
                                </button>
                                {` — ${batch.is_sent ? 'enviado/finalizado' : 'adicionado e pendente de envio'}`}
                              </p>
                            )) : (
                              <p><strong>Lote da devolucao:</strong> nenhum</p>
                            )}
                          </>
                        ) : (
                          <p><strong>Eventos:</strong> sem ocorrencia/devolucao registrada para esta NF.</p>
                        )}
                      </div>
                    </div>
                    <TotalQuantity className="mt-2 shrink-0 flex items-center justify-between gap-2">
                      <p>Use o botao Voltar</p>
                      <button
                        type="button"
                        onClick={() => toggleFlip(key)}
                        className="inline-flex h-7 shrink-0 items-center rounded-md border border-border bg-surface-2/85 px-2 text-[11px] font-semibold text-text transition hover:border-accent/60 hover:text-text-accent"
                        aria-label={`Voltar para frente do card da NF ${danfe.invoice_number}`}
                      >
                        Voltar
                      </button>
                    </TotalQuantity>
                  </CardsDanfe>
                </div>
              </div>
            );
          })}
        </ContainerCards>
      ) : (
        <div className="mx-auto w-full max-w-[1200px] rounded-lg border semantic-panel-neutral px-4 py-6 text-center text-sm">
          Nenhuma NF corresponde ao filtro de borda selecionado.
        </div>
      )}

      {productsModalDanfe ? (
        <div className="fixed inset-0 z-[1400] flex items-center justify-center p-3">
          <button
            type="button"
            aria-label="Fechar lista de produtos"
            className="absolute inset-0 bg-slate-950/80"
            onClick={closeProductsModal}
          />
          <div className="relative z-[1410] flex max-h-[88vh] w-full max-w-[680px] flex-col rounded-lg border border-border bg-card p-3 text-text shadow-[0_14px_34px_rgba(0,0,0,0.55)]">
            <div className="flex items-start justify-between gap-2">
              <div>
                <h3 className="text-base font-semibold">{`NF ${productsModalDanfe.invoice_number}`}</h3>
                <p className="text-xs text-muted">
                  {`${normalizeTextValue(productsModalDanfe.Customer?.name_or_legal_entity) || '-'} | ${normalizeCityLabel(productsModalDanfe.Customer?.city) || '-'}`}
                </p>
              </div>
              <button
                type="button"
                onClick={closeProductsModal}
                className="inline-flex h-8 items-center rounded-md border border-border bg-surface-2/85 px-2 text-xs font-semibold text-text transition hover:border-accent/60 hover:text-text-accent"
              >
                Fechar
              </button>
            </div>

            <div className="mt-3 flex min-h-0 flex-1 flex-col overflow-hidden rounded-md border border-border bg-surface-2/65 p-2">
              <DescriptionColumns className="shrink-0 pr-1">
                <span>Codigo</span>
                <span>Descricao</span>
                <span>Qtd</span>
              </DescriptionColumns>
              <div className="scrollbar-ui mt-1 min-h-0 flex-1 overflow-y-auto pr-1">
                {productsModalDanfe.DanfeProducts.map((item) => (
                  <ListItems key={`modal-${productsModalDanfe.invoice_number}-${item.Product.code}`}>
                    <li>{item.Product.code}</li>
                    <li title={normalizeTextValue(item.Product.description)}>{normalizeTextValue(item.Product.description)}</li>
                    <li>{formatQuantity(item.quantity, item.type)}</li>
                  </ListItems>
                ))}
              </div>
            </div>

            <p className="mt-2 text-xs font-medium text-muted">
              {`Total de itens: ${productsModalDanfe.DanfeProducts.length}`}
            </p>
          </div>
        </div>
      ) : null}

      {replacementModalDanfe ? (
        <div className="fixed inset-0 z-[1415] flex items-center justify-center p-3">
          <button
            type="button"
            aria-label="Fechar vinculo de refaturamento"
            className="absolute inset-0 bg-slate-950/80"
            onClick={() => closeReplacementModal()}
          />
          <div className="relative z-[1420] flex w-full max-w-[520px] flex-col rounded-lg border border-border bg-card p-4 text-text shadow-[0_14px_34px_rgba(0,0,0,0.55)]">
            <div className="flex items-start justify-between gap-2">
              <div>
                <h3 className="text-base font-semibold">{`NF ${replacementModalDanfe.invoice_number}`}</h3>
                <p className="text-xs text-muted">Vincule a NF nova para manter o refaturamento visivel na busca da expedicao.</p>
              </div>
              <button
                type="button"
                onClick={() => closeReplacementModal()}
                className="inline-flex h-8 items-center rounded-md border border-border bg-surface-2/85 px-2 text-xs font-semibold text-text transition hover:border-accent/60 hover:text-text-accent disabled:opacity-50"
                disabled={isLinkingReplacement}
              >
                Fechar
              </button>
            </div>

            <label className="mt-3 text-xs text-muted">
              NF substituta
              <input
                value={replacementInvoiceInput}
                onChange={(event) => setReplacementInvoiceInput(event.target.value)}
                className="mt-1 h-10 w-full rounded-sm border border-border bg-surface-2/85 px-3 text-sm text-text"
                placeholder="Ex.: 1722999"
              />
            </label>

            <label className="mt-3 text-xs text-muted">
              Motivo/observacao
              <input
                value={replacementReasonInput}
                onChange={(event) => setReplacementReasonInput(event.target.value)}
                className="mt-1 h-10 w-full rounded-sm border border-border bg-surface-2/85 px-3 text-sm text-text"
                placeholder="Refaturada"
              />
            </label>

            {replacementError ? (
              <div className="mt-3 rounded-md border semantic-panel-danger px-3 py-2 text-sm">
                {replacementError}
              </div>
            ) : null}

            <div className="mt-4 flex justify-end gap-2">
              <button
                type="button"
                onClick={() => closeReplacementModal()}
                className="rounded-md border border-border bg-surface-2 px-3 py-2 text-sm text-text"
                disabled={isLinkingReplacement}
              >
                Cancelar
              </button>
              <button
                type="button"
                onClick={handleLinkReplacementInvoice}
                className="rounded-md border border-border bg-gradient-to-r from-accent to-accent-strong px-4 py-2 text-sm font-semibold text-[#04131e] disabled:opacity-60"
                disabled={isLinkingReplacement}
              >
                {isLinkingReplacement ? 'Vinculando...' : 'Salvar vinculo'}
              </button>
            </div>
          </div>
        </div>
      ) : null}

      {assignmentModalDanfe ? (
        <div className="fixed inset-0 z-[1400] flex items-center justify-center p-3">
          <button
            type="button"
            aria-label="Fechar atribuição de rota"
            className="absolute inset-0 bg-slate-950/80"
            onClick={() => closeAssignmentModal()}
          />
          <div className="relative z-[1410] flex max-h-[88vh] w-full max-w-[520px] flex-col rounded-lg border border-border bg-card p-4 text-text shadow-[0_14px_34px_rgba(0,0,0,0.55)]">
            <div className="flex items-start justify-between gap-3">
              <div>
                <h3 className="text-base font-semibold">{`Atribuir NF ${assignmentModalDanfe.invoice_number}`}</h3>
                <p className="text-xs text-muted">
                  {`${normalizeTextValue(assignmentModalDanfe.Customer?.name_or_legal_entity) || '-'} | ${normalizeCityLabel(assignmentModalDanfe.Customer?.city) || '-'}`}
                </p>
              </div>
              <button
                type="button"
                onClick={() => closeAssignmentModal()}
                className="inline-flex h-8 items-center rounded-md border border-border bg-surface-2/85 px-2 text-xs font-semibold text-text transition hover:border-accent/60 hover:text-text-accent"
              >
                Fechar
              </button>
            </div>

            <div className="mt-3 space-y-2 overflow-y-auto pr-1">
              {assignableTrips.map((trip) => {
                const tripId = String(trip.id);
                const isSelected = selectedTripId === tripId;

                return (
                  <button
                    key={`assign-trip-${trip.id}`}
                    type="button"
                    onClick={() => setSelectedTripId(tripId)}
                    className={cn(
                      'w-full rounded-lg border px-3 py-2 text-left transition',
                      isSelected
                        ? 'border-accent bg-accent/10'
                        : 'border-border bg-surface-2/70 hover:border-accent/45 hover:bg-surface-2',
                    )}
                  >
                    <div className="flex items-center justify-between gap-3">
                      <div className="min-w-0">
                        <p className="truncate text-sm font-semibold text-text">{trip.Driver?.name || `Motorista #${trip.driver_id}`}</p>
                        <p className="truncate text-xs text-muted">
                          {`${trip.Car?.license_plate || '-'} | saída #${trip.run_number || 1} | ${trip.TripNotes?.length || 0} nota(s)`}
                        </p>
                      </div>
                      <span className={cn(
                        'inline-flex h-5 w-5 shrink-0 items-center justify-center rounded-full border text-[11px] font-bold',
                        isSelected ? 'border-accent bg-accent text-[#04131e]' : 'border-border text-muted',
                      )}
                      >
                        {isSelected ? '✓' : ''}
                      </span>
                    </div>
                  </button>
                );
              })}
            </div>

            {assignmentError ? (
              <p className="mt-3 rounded-md border border-rose-500/40 bg-rose-500/10 px-2 py-2 text-xs text-rose-100">
                {assignmentError}
              </p>
            ) : null}

            <div className="mt-4 flex items-center justify-end gap-2">
              <button
                type="button"
                onClick={() => closeAssignmentModal()}
                className="inline-flex h-9 items-center rounded-md border border-border bg-surface-2/85 px-3 text-sm font-semibold text-text transition hover:border-accent/60 hover:text-text-accent"
                disabled={isAssigningDanfe}
              >
                Cancelar
              </button>
              <button
                type="button"
                onClick={handleAssignDanfeToTrip}
                className="inline-flex h-9 items-center rounded-md border border-border bg-gradient-to-r from-accent to-accent-strong px-3 text-sm font-semibold text-[#04131e] transition disabled:opacity-60"
                disabled={isAssigningDanfe}
              >
                {isAssigningDanfe ? 'Atribuindo...' : 'Confirmar atribuição'}
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </>
  );
}

export default memo(CardDanfes);
